     1→import { createContext, useContext, useEffect, useState } from 'react';
     2→
     3→type Theme = 'dark' | 'light';
     4→
     5→interface ThemeContextValue {
     6→  theme: Theme;
     7→  toggleTheme: () => void;
     8→}
     9→
    10→const ThemeContext = createContext<ThemeContextValue>({
    11→  theme: 'dark',
    12→  toggleTheme: () => {},
    13→});
    14→
    15→export function ThemeProvider({ children }: { children: React.ReactNode }) {
    16→  const [theme, setTheme] = useState<Theme>(() => {
    17→    if (typeof window !== 'undefined') {
    18→      return (localStorage.getItem('fde-theme') as Theme) || 'dark';
    19→    }
    20→    return 'dark';
    21→  });
    22→
    23→  useEffect(() => {
    24→    const root = document.documentElement;
    25→    if (theme === 'light') {
    26→      root.classList.add('light');
    27→      root.classList.remove('dark');
    28→    } else {
    29→      root.classList.add('dark');
    30→      root.classList.remove('light');
    31→    }
    32→    localStorage.setItem('fde-theme', theme);
    33→  }, [theme]);
    34→
    35→  const toggleTheme = () => setTheme(t => (t === 'dark' ? 'light' : 'dark'));
    36→
    37→  return (
    38→    <ThemeContext.Provider value={{ theme, toggleTheme }}>
    39→      {children}
    40→    </ThemeContext.Provider>
    41→  );
    42→}
    43→
    44→export const useTheme = () => useContext(ThemeContext);
    45→

